181	func populateFields(base Base, v reflect.Value, tags ...Tag) reflect.Value {
182		t := v.Type()
183	
184		if t.Kind() == reflect.Struct {
185			allNil := true
186			for i := range t.NumField() {
187				tt := t.Field(i).Type
188				vv := v.Field(i)
189				if !vv.CanSet() {
190					continue
191				}
192	
193				// make a copy
194				tagsCopy := tags
195				if tag := t.Field(i).Tag.Get("gguf"); tag != "" {
196					tagsCopy = append(tagsCopy, parseTag(tag))
197				}
198	
199				if tt == reflect.TypeOf((*Base)(nil)).Elem() {
200					vv.Set(reflect.ValueOf(base))
201				} else if tt == reflect.TypeOf((*ml.Tensor)(nil)).Elem() {
202					var fn func([]Tag, string, string) [][]string
203					fn = func(tags []Tag, prefix, suffix string) (fullNames [][]string) {
204						if len(tags) > 0 {
205							var names []string
206							if tags[0].name != "" {
207								for _, n := range append([]string{tags[0].name}, tags[0].alternatives...) {
208									names = append(names, prefix+n+suffix)
209								}
210							}
211							childNames := fn(tags[1:], tags[0].prefix, tags[0].suffix)
212							if len(names) == 0 {
213								// current tag has no name, use child names only
214								fullNames = append(fullNames, childNames...)
215							} else if len(childNames) == 0 {
216								// current tag has names but no children, create branches for each name
217								for _, name := range names {
218									fullNames = append(fullNames, []string{name})
219								}
220							} else {
221								// merge each name with each child
222								for _, name := range names {
223									for _, childName := range childNames {
224										fullNames = append(fullNames, append([]string{name}, childName...))
225									}
226								}
227							}
228						}
229	
230						return fullNames
231					}
232	
233					names := fn(tagsCopy, "", "")
234					for _, name := range names {
235						if tensor := base.Backend().Get(strings.Join(name, ".")); tensor != nil {
236							logutil.Trace("found tensor", "", tensor)
237							vv.Set(reflect.ValueOf(tensor))
238							break
239						}
240					}
241				} else if tt.Kind() == reflect.Pointer || tt.Kind() == reflect.Interface {
242					setPointer(base, vv, tagsCopy)
243				} else if tt.Kind() == reflect.Slice || tt.Kind() == reflect.Array {
244					for i := range vv.Len() {
245						vvv := vv.Index(i)
246						if vvv.Kind() == reflect.Pointer || vvv.Kind() == reflect.Interface {
247							setPointer(base, vvv, append(tagsCopy, Tag{name: strconv.Itoa(i)}))
248						} else {
249							vvv.Set(populateFields(base, vvv, append(tagsCopy, Tag{name: strconv.Itoa(i)})...))
250						}
251					}
252				}
253	
254				if !canNil(tt) || !vv.IsNil() {
255					allNil = false
256				}
257			}
258	
259			if allNil {
260				return reflect.Zero(t)
261			}
262		}
263	
264		return v
265	}
266	
267	func setPointer(base Base, v reflect.Value, tags []Tag) {
268		vv := v
269		if v.Kind() == reflect.Interface {
270			if v.IsNil() {
271				return
272			}
273	
274			vv = vv.Elem()
275		}
276	
277		vv = reflect.Indirect(vv)
278		if v.IsNil() {
279			vv = reflect.New(v.Type().Elem()).Elem()
280		}
281	
282		if f := populateFields(base, vv, tags...); f.CanAddr() {
283			v.Set(f.Addr())
284		}
285	}
