287	type Tag struct {
288		name,
289		// prefix and suffix are applied to child tags
290		prefix,
291		suffix string
292		alternatives []string
293	}
294	
295	func parseTag(s string) (tag Tag) {
296		parts := strings.Split(s, ",")
297		if len(parts) > 0 {
298			tag.name = parts[0]
299	
300			for _, part := range parts[1:] {
301				if value, ok := strings.CutPrefix(part, "alt:"); ok && tag.name == "" {
302					// elevate alternative to primary if no primary given
303					tag.name = value
304					slog.Warn("gguf tag has alt: but no primary name", "tag", s)
305				} else if ok {
306					tag.alternatives = append(tag.alternatives, value)
307				}
308				if value, ok := strings.CutPrefix(part, "pre:"); ok {
309					tag.prefix = value
310				}
311				if value, ok := strings.CutPrefix(part, "suf:"); ok {
312					tag.suffix = value
313				}
314			}
315		}
316	
317		return
318	}
319	
320	func canNil(t reflect.Type) bool {
321		return t.Kind() == reflect.Chan ||
322			t.Kind() == reflect.Func ||
323			t.Kind() == reflect.Interface ||
324			t.Kind() == reflect.Map ||
325			t.Kind() == reflect.Pointer ||
326			t.Kind() == reflect.Slice
327	}
