329	func Forward(ctx ml.Context, m Model, batch input.Batch) (ml.Tensor, error) {
330		if len(batch.Positions) != len(batch.Sequences) {
331			return nil, fmt.Errorf("length of positions (%v) must match length of seqs (%v)", len(batch.Positions), len(batch.Sequences))
332		}
333	
334		if len(batch.Positions) < 1 {
335			return nil, errors.New("batch size cannot be less than 1")
336		}
337	
338		cache := m.Config().Cache
339		if cache != nil {
340			err := cache.StartForward(ctx, batch, false)
341			if err != nil {
342				return nil, err
343			}
344		}
345	
346		t, err := m.Forward(ctx, batch)
347		if err != nil {
348			return nil, err
349		}
350	
351		ctx.Forward(t)
352	
353		return t, nil
354	}
