// RenameModel renames a model by copying its manifest to the destination name
// and then removing the source manifest. The underlying layer blobs are shared
// and are never duplicated or deleted.
func RenameModel(src, dst model.Name) error {
	if !dst.IsFullyQualified() {
		return model.Unqualified(dst)
	}
	if !src.IsFullyQualified() {
		return model.Unqualified(src)
	}

	if err := CopyModel(src, dst); err != nil {
		return err
	}

	srcManifest, err := manifest.ParseNamedManifest(src)
	if err != nil {
		return err
	}

	return srcManifest.Remove()
}

